package com.banking.service;

import com.banking.model.TransactionRequest;
import com.banking.model.TransactionResponse;

import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebResult;
import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;

@WebService(targetNamespace = "http://service.banking.com/",
            name = "BankingService")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public interface BankingService {

    @WebMethod(operationName = "ProcessTransaction")
    @WebResult(name = "TransactionResult")
    TransactionResponse processTransaction(
            @WebParam(name = "TransactionDetails") TransactionRequest request);
}

