package com.banking.service;

import com.banking.model.TransactionRequest;
import com.banking.model.TransactionResponse;
import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.frontend.MethodDispatcher;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.message.Exchange;
import org.apache.cxf.message.Message;
import org.apache.cxf.service.Service;
import org.apache.cxf.service.model.BindingOperationInfo;
import org.apache.cxf.service.model.OperationInfo;
import org.apache.cxf.ws.security.SecurityConstants;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.Document;

import javax.annotation.Resource;
import javax.xml.ws.WebServiceContext;
import java.util.List;
import java.util.Map;

public class BankingServiceImpl implements BankingService {

    private static final Logger LOG = LoggerFactory.getLogger(BankingServiceImpl.class);

    @Resource
    private WebServiceContext wsContext;

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        LOG.info("Received transaction request for ID: {} from account: {}", request.getTransactionId(), request.getAccountNumber());
        LOG.debug("Transaction details: {}", request);

        // Retrieve WS-Security information if needed (e.g., to confirm signature properties)
        // This is mainly for demonstrating how to access security context.
        // CXF's WSS4JInInterceptor already verified the signature BEFORE this method is called.
        Message message = wsContext.getMessageContext() != null ? (Message) wsContext.getMessageContext().get(Message.class.getName()) : null;

        if (message != null) {
            Map<String, Object> securityProps = (Map<String, Object>)message.get(SecurityConstants.SIGNATURE_PROPERTIES);
            if (securityProps != null && securityProps.containsKey("org.apache.ws.security.crypto.merlin.file")) {
                LOG.info("Signature verification used keystore: {}", securityProps.get("org.apache.ws.security.crypto.merlin.file"));
            }

            // You can also check which parts were signed, though CXF's interceptor handles the
            // verification of the integrity of the message body.
            // List<String> signedParts = (List<String>) message.get(SecurityConstants.SIGNATURE_PARTS);
            // LOG.debug("Signed parts: {}", signedParts);
        }

        // Simulate banking transaction processing
        try {
            // Add your business logic here for processing the transaction
            // e.g., validate account, check balance, update ledger, etc.
            if (request.getAmount() == null || request.getAmount().signum() <= 0) {
                return new TransactionResponse(request.getTransactionId(), "FAILED", "Invalid transaction amount.");
            }
            if (!isValidAccountNumber(request.getAccountNumber())) {
                return new TransactionResponse(request.getTransactionId(), "FAILED", "Invalid account number.");
            }

            LOG.info("Transaction ID {} processed successfully for account {}", request.getTransactionId(), request.getAccountNumber());
            return new TransactionResponse(request.getTransactionId(), "SUCCESS", "Transaction processed successfully.");

        } catch (Exception e) {
            LOG.error("Error processing transaction ID {}: {}", request.getTransactionId(), e.getMessage(), e);
            return new TransactionResponse(request.getTransactionId(), "FAILED", "Internal server error: " + e.getMessage());
        }
    }

    private boolean isValidAccountNumber(String accountNumber) {
        // Simple validation for demonstration purposes
        return accountNumber != null && accountNumber.matches("\\d{10,12}");
    }
}

