package com.banking.service;

import org.springframework.context.support.ClassPathXmlApplicationContext;

public class BankingServicePublisher {

    public static void main(String[] args) {
        // Load the Spring context which defines the CXF endpoint
        System.out.println("Starting Banking Service...");
        ClassPathXmlApplicationContext context =
                new ClassPathXmlApplicationContext("beans.xml");
        System.out.println("Banking Service started. Press Enter to stop...");
        try {
            System.in.read();
        } catch (Exception e) {
            e.printStackTrace();
        }
        context.close();
        System.out.println("Banking Service stopped.");
    }
}

