package com.banking.service;

import org.apache.ws.security.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;

public class ServerPasswordCallback implements CallbackHandler {

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (int i = 0; i < callbacks.length; i++) {
            WSPasswordCallback pc = (WSPasswordCallback) callbacks[i];

            // For signing outgoing messages by the server
            if ("serverkey".equals(pc.getIdentifier())) { // This is the alias of the server's private key
                pc.setPassword("serverpass"); // Password for the server's private key
            }
            // For decrypting incoming messages (if encryption were configured)
            // else if ("serverkey".equals(pc.getIdentifier())) { // Alias of the server's decryption key
            //    pc.setPassword("serverpass");
            // }
        }
    }
}